#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>
#include <string.h>
static unsigned char buf[8];
static int len;
int run_decomp(unsigned char *b,int n){
 int p[2]; if(pipe(p)) return -1;
 FILE *in=fdopen(p[1],"wb"); if(!in){close(p[0]);close(p[1]);return -1;}
 fwrite(b,1,n,in); fflush(in); fclose(p[1]);
 FILE *out=fdopen(p[0],"rb");
 unsigned char r[16]; int got=0,ch;
 while((ch=fgetc(out))!=EOF && got<16) r[got++]=ch;
 fclose(out);
 return got==1 && r[0]==1;
}
int main(){
 for(len=1;len<=3;len++){
  long total=1; for(int i=0;i<len*8;i++) total*=2;
  for(long v=0;v<total;v++){
   long x=v; for(int i=0;i<len;i++){buf[i]=x&0xff;x>>=8;}
   if(run_decomp(buf,len)){ printf("FOUND len=%d bytes",len); for(int i=0;i<len;i++) printf(" %02x",buf[i]); printf("\n"); fflush(stdout); }
  }
 }
 // sampled 4-byte search
 for(long s=0;s<2000000L;s++){
  long x=s*1234577+1; for(int i=0;i<4;i++){buf[i]=x&0xff;x>>=8;}
  if(run_decomp(buf,4)){ printf("FOUND4 bytes",0); for(int i=0;i<4;i++) printf(" %02x",buf[i]); printf("\n"); fflush(stdout); }
 }
 return 0;
}
